#!/usr/bin/env python3
"""Comprehensive test for primary store feature."""

import subprocess
import json
import sys
import os
import time
import threading
import http.server
import socketserver
import urllib.parse

# In-memory store for testing
TEST_STORE = {
    "app/port": "9090",
    "app/debug": "true",
    "config/retries": "3",
    "app/timeout": "30.5",
    "config/nonexistent": None,  # Will 404
}

PORT = 8502

class TestHandler(http.server.BaseHTTPRequestHandler):
    def do_GET(self):
        if self.path.startswith('/v1/primary/kv?key='):
            query = self.path.split('?', 1)[1]
            if query.startswith('key='):
                key = urllib.parse.unquote(query[4:])
                if key in TEST_STORE and TEST_STORE[key] is not None:
                    self.send_response(200)
                    self.send_header('Content-Type', 'application/json')
                    self.end_headers()
                    resp = {"found": True, "value": TEST_STORE[key], "version": 1}
                    self.wfile.write(json.dumps(resp).encode())
                else:
                    self.send_response(404)
                    self.send_header('Content-Type', 'application/json')
                    self.end_headers()
                    self.wfile.write(json.dumps({'found': False}).encode())
            else:
                self.send_response(400)
                self.end_headers()
        else:
            self.send_response(404)
            self.end_headers()
    def log_message(self, f, *a): pass

def run_server():
    with socketserver.TCPServer(('127.0.0.1', PORT), TestHandler) as httpd:
        httpd.serve_forever()

def run_test(args, expected_output, expected_error=None):
    """Run cfgpipe with given args and check output."""
    cmd = ["/workspace/venv/bin/python", "/workspace/cfgpipe.py"] + args
    result = subprocess.run(cmd, capture_output=True, text=True)

    if expected_error:
        if result.returncode == 0:
            print(f"FAIL: Expected error but succeeded: {' '.join(args)}")
            print(f"  Output: {result.stdout}")
            return False
        else:
            if expected_error in result.stderr:
                print(f"PASS: Got expected error: {' '.join(args)}")
                return True
            else:
                print(f"FAIL: Expected error '{expected_error}' but got: {result.stderr}")
                return False
    else:
        if result.returncode != 0:
            print(f"FAIL: Command failed: {' '.join(args)}")
            print(f"  Error: {result.stderr}")
            return False
        try:
            actual = json.loads(result.stdout)
            expected = json.loads(expected_output)
            if actual == expected:
                print(f"PASS: Output matches: {' '.join(args)}")
                return True
            else:
                print(f"FAIL: Output mismatch for: {' '.join(args)}")
                print(f"  Expected: {expected}")
                print(f"  Got: {actual}")
                return False
        except json.JSONDecodeError as e:
            print(f"FAIL: Invalid JSON output: {result.stdout}")
            return False

def main():
    # Start test server in background
    server_thread = threading.Thread(target=run_server, daemon=True)
    server_thread.start()
    time.sleep(0.5)  # Give server time to start

    base_url = f"http://127.0.0.1:{PORT}"
    all_passed = True

    # Test 1: Example 7.1 - Primary store overrides default
    schema = {
        "port": {"type": "integer", "default": "3000", "primary-store": "app/port"},
        "host": {"type": "string", "default": "localhost"}
    }
    with open("/tmp/test1.json", "w") as f:
        json.dump(schema, f)

    all_passed &= run_test(
        [f"--primary-store", base_url, "/tmp/test1.json"],
        '{"port": "9090", "host": "localhost"}'
    )

    # Test 2: Missing key falls through to default
    schema = {
        "retries": {"type": "integer", "default": "3", "primary-store": "config/retries"}
    }
    with open("/tmp/test2.json", "w") as f:
        json.dump(schema, f)

    all_passed &= run_test(
        [f"--primary-store", base_url, "/tmp/test2.json"],
        '{"retries": "3"}'
    )

    # Test 3: Missing store configuration is fatal
    schema = {
        "timeout": {"type": "float", "primary-store": "app/timeout"}
    }
    with open("/tmp/test3.json", "w") as f:
        json.dump(schema, f)

    all_passed &= run_test(
        ["/tmp/test3.json"],
        None,
        "Parameter 'timeout' requires --primary-store flag"
    )

    # Test 4: Primary store override with env still present
    schema = {
        "port": {"type": "integer", "default": "3000", "env": "APP_PORT", "primary-store": "app/port"}
    }
    with open("/tmp/test4.json", "w") as f:
        json.dump(schema, f)

    # Without env var, should use primary store
    os.environ.pop("APP_PORT", None)
    all_passed &= run_test(
        [f"--primary-store", base_url, "/tmp/test4.json"],
        '{"port": "9090"}'
    )

    # With env var, env should be overridden by primary store
    os.environ["APP_PORT"] = "7777"
    all_passed &= run_test(
        [f"--primary-store", base_url, "/tmp/test4.json"],
        '{"port": "9090"}'
    )

    # Test 5: CLI arg should override primary store
    all_passed &= run_test(
        [f"--primary-store", base_url, "/tmp/test4.json", "port=5555"],
        '{"port": "5555"}'
    )

    # Test 6: Duplicate primary-store keys should fail schema validation
    schema = {
        "port": {"type": "integer", "primary-store": "config/param"},
        "host": {"type": "string", "primary-store": "config/param"}
    }
    with open("/tmp/test6.json", "w") as f:
        json.dump(schema, f)

    all_passed &= run_test(
        ["/tmp/test6.json"],
        None,
        "Parameters share duplicate primary-store key"
    )

    # Test 7: Boolean type from primary store
    schema = {
        "debug": {"type": "boolean", "default": "false", "primary-store": "app/debug"}
    }
    with open("/tmp/test7.json", "w") as f:
        json.dump(schema, f)

    all_passed &= run_test(
        [f"--primary-store", base_url, "/tmp/test7.json"],
        '{"debug": "true"}'
    )

    # Test 8: Invalid type from primary store should be fatal
    TEST_STORE["app/invalid"] = "not_a_number"
    schema = {
        "port": {"type": "integer", "primary-store": "app/invalid"}
    }
    with open("/tmp/test8.json", "w") as f:
        json.dump(schema, f)

    all_passed &= run_test(
        [f"--primary-store", base_url, "/tmp/test8.json"],
        None,
        "primary-store parse error"
    )

    # Test 9: Key that doesn't exist falls through to nothing (should error)
    schema = {
        "port": {"type": "integer", "primary-store": "app/nonexistent"}
    }
    with open("/tmp/test9.json", "w") as f:
        json.dump(schema, f)

    all_passed &= run_test(
        [f"--primary-store", base_url, "/tmp/test9.json"],
        None,
        "Unresolved parameter: port"
    )

    print("\n" + "="*50)
    if all_passed:
        print("ALL TESTS PASSED")
    else:
        print("SOME TESTS FAILED")
    print("="*50)

    sys.exit(0 if all_passed else 1)

if __name__ == "__main__":
    main()

